Good call. I can instead do:

if (!mem_cgroup_disabled() && root_mem_cgroup) {
	struct mem_cgroup *memcg;
	struct lruvec *lruvec;
	/* use lruvec for updating stats */
} else {
	/* use node for updating stats */
}

This should also take care of the bot warning on mem_cgroup_from_task()
not being available.

Subject changed to "btrfs: check block group before marking it unused in
balance_remap_chunks()"

On Mon, Mar 09, 2026 at 06:50:37PM +0000, Mark Harmstone wrote:
> Fix a potential segfault in balance_remap_chunks(): if we quit early
> because btrfs_inc_block_group_ro() fails, all the remaining items in the
> chunks list will still have their bg value set to NULL. It's thus not
> safe to dereference this pointer without checking first.
> 
> Link: https://lore.kernel.org/linux-btrfs/20260125120717.1578828-1-clm@meta.com/
> Reported-by: Chris Mason <clm@fb.com>
> Fixes: 81e5a4551c32 ("btrfs: allow balancing remap tree")
> Signed-off-by: Mark Harmstone <mark@harmstone.com>
> ---
>  fs/btrfs/volumes.c | 20 ++++++++++++--------
>  1 file changed, 12 insertions(+), 8 deletions(-)
> 
> diff --git a/fs/btrfs/volumes.c b/fs/btrfs/volumes.c
> index 95accc9361bd26..aff286d9df4aa0 100644
> --- a/fs/btrfs/volumes.c
> +++ b/fs/btrfs/volumes.c
> @@ -4285,20 +4285,24 @@ static int balance_remap_chunks(struct btrfs_fs_info *fs_info, struct btrfs_path
>  end:
>  	while (!list_empty(chunks)) {
>  		bool is_unused;
> +		struct btrfs_block_group *bg;
>  
>  		rci = list_first_entry(chunks, struct remap_chunk_info, list);
>  
> -		spin_lock(&rci->bg->lock);
> -		is_unused = !btrfs_is_block_group_used(rci->bg);
> -		spin_unlock(&rci->bg->lock);
> +		bg = rci->bg;
> +		if (bg) {
> +			spin_lock(&bg->lock);
> +			is_unused = !btrfs_is_block_group_used(bg);
> +			spin_unlock(&bg->lock);
>  
> -		if (is_unused)
> -			btrfs_mark_bg_unused(rci->bg);
> +			if (is_unused)
> +				btrfs_mark_bg_unused(bg);
>  
> -		if (rci->made_ro)
> -			btrfs_dec_block_group_ro(rci->bg);
> +			if (rci->made_ro)
> +				btrfs_dec_block_group_ro(bg);
>  
> -		btrfs_put_block_group(rci->bg);
> +			btrfs_put_block_group(bg);
> +		}
>  
>  		list_del(&rci->list);
>  		kfree(rci);
> -- 
> 2.52.0
>

Subject changed to btrfs: hold block group reference during entire
move_existing_remap()"

On Fri, Mar 06, 2026 at 02:18:31PM +0000, Mark Harmstone wrote:
> There is a potential use-after-free in move_existing_remap(): we're calling
> btrfs_put_block_group() on dest_bg, then passing it to
> btrfs_add_block_group_free_space() a few lines later.
> 
> Fix this by getting the BG at the start of the function and putting it
> near the end. This also means we're not doing a lookup twice for the
> same thing.
> 
> Link: https://lore.kernel.org/linux-btrfs/20260125123908.2096548-1-clm@meta.com/
> Reported-by: Chris Mason <clm@fb.com>
> Fixes: bbea42dfb91f ("btrfs: move existing remaps before relocating block group")
> Signed-off-by: Mark Harmstone <mark@harmstone.com>
> ---
>  fs/btrfs/relocation.c | 9 ++++-----
>  1 file changed, 4 insertions(+), 5 deletions(-)
> 
> diff --git a/fs/btrfs/relocation.c b/fs/btrfs/relocation.c
> index 88b1ec416fe272..1c42c5180bddd5 100644
> --- a/fs/btrfs/relocation.c
> +++ b/fs/btrfs/relocation.c
> @@ -4177,6 +4177,8 @@ static int move_existing_remap(struct btrfs_fs_info *fs_info,
>  	dest_addr = ins.objectid;
>  	dest_length = ins.offset;
>  
> +	dest_bg = btrfs_lookup_block_group(fs_info, dest_addr);
> +
>  	if (!is_data && !IS_ALIGNED(dest_length, fs_info->nodesize)) {
>  		u64 new_length = ALIGN_DOWN(dest_length, fs_info->nodesize);
>  
> @@ -4287,15 +4289,12 @@ static int move_existing_remap(struct btrfs_fs_info *fs_info,
>  	if (unlikely(ret))
>  		goto end;
>  
> -	dest_bg = btrfs_lookup_block_group(fs_info, dest_addr);
> -
>  	adjust_block_group_remap_bytes(trans, dest_bg, dest_length);
>  
>  	mutex_lock(&dest_bg->free_space_lock);
>  	bg_needs_free_space = test_bit(BLOCK_GROUP_FLAG_NEEDS_FREE_SPACE,
>  				       &dest_bg->runtime_flags);
>  	mutex_unlock(&dest_bg->free_space_lock);
> -	btrfs_put_block_group(dest_bg);
>  
>  	if (bg_needs_free_space) {
>  		ret = btrfs_add_block_group_free_space(trans, dest_bg);
> @@ -4325,13 +4324,13 @@ static int move_existing_remap(struct btrfs_fs_info *fs_info,
>  			btrfs_end_transaction(trans);
>  		}
>  	} else {
> -		dest_bg = btrfs_lookup_block_group(fs_info, dest_addr);
>  		btrfs_free_reserved_bytes(dest_bg, dest_length, 0);
> -		btrfs_put_block_group(dest_bg);
>  
>  		ret = btrfs_commit_transaction(trans);
>  	}
>  
> +	btrfs_put_block_group(dest_bg);
> +
>  	return ret;
>  }
>  
> -- 
> 2.52.0
>
